#!/bin/bash
# Self-contained setup: extracts Buddlys Node server and starts it on port 3000.
# OmniVoice TTS must already be running on port 8000.
# Usage: bash runpod-setup.sh
set -e

# 1. Install Node.js 20 if missing
if ! command -v node &> /dev/null; then
  echo "[setup] Installing Node.js 20..."
  curl -fsSL https://deb.nodesource.com/setup_20.x | bash -
  apt-get install -y nodejs
fi
echo "[setup] Node $(node -v), npm $(npm -v)"

# 2. Extract server code into /workspace/
echo "[setup] Extracting server code..."
mkdir -p /workspace
echo '' | base64 -d | tar -xz -C /workspace/

# 3. Write .env  (PORT=3000, OmniVoice points to local port 8000)
cat > /workspace/server/.env << 'EOF'
MISTRAL_API_KEY=NWGzc8WkeAuui2KD1ZGpQ1q1B32JQXk3
MISTRAL_MODEL=magistral-small-2509
CARTESIA_API_KEY=sk_car_fwcH6DVbBWxDpH8F92Um63
CARTESIA_VOICE_ID=7f88148a-347b-4fbc-954a-018117844e06
CARTESIA_MODEL=sonic-3.5
CARTESIA_LANGUAGE=de
CARTESIA_SPEED=0.85
TAVILY_API_KEY=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
MISTRAL_TTS_MODEL=voxtral-mini-tts-2603
MISTRAL_TTS_VOICE=Stimme Buddly
MISTRAL_TTS_FORMAT=wav
MISTRAL_STT_MODEL=voxtral-mini-2507
MISTRAL_STT_LANGUAGE=de
PORT=3000
OMNIVOICE_HTTP_URL=http://localhost:8000
EOF

# 4. Install deps and start
cd /workspace/server
echo "[setup] npm install..."
npm install
echo "[setup] Starting on port 3000..."
npx tsx src/index.ts
